# Category: sns_topic_open_subscription

import boto3
import os

def lambda_handler(event, context):
    sns_client = boto3.client('sns', region_name=os.environ['AWS_REGION'])
    
    message = event.get('message')
    topic_arn = event.get('topic_arn')
    notification_type = event.get('notification_type', 'default')

    if not message or not topic_arn:
        raise ValueError("Message and Topic ARN must be provided")

    try:
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=message,
            MessageAttributes={
                'notificationType': {
                    'DataType': 'String',
                    'StringValue': notification_type
                }
            }
        )
        return {
            'statusCode': 200,
            'body': f"Message published to {topic_arn} with ID: {response['MessageId']}"
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': f"Failed to publish message: {str(e)}"
        }